const url = new URL("https://games.bisecthosting.com/api/client");

let params = {
    "type": "owner",
    "filter[*]": "filter[name]=Test",
    "filter[uuid]": "1234-5678-9101",
    "filter[name]": "My Server",
    "filter[description]": "Development",
    "filter[external_id]": "ext123",
    "filter[subdomain]": "play.example.com",
    "filter[location_ids]": "filter[location_ids][]=1&amp;filter[location_ids][]=2",
    "filter[egg_ids]": "filter[egg_ids][]=5&amp;filter[egg_ids][]=10",
    "filter[jar_ids]": "filter[jar_ids][]=3&amp;filter[jar_ids][]=7",
    "per_page": "50",
    "page": "1",
    "include": "node",
};

Object.keys(params).forEach(key => url.searchParams.append(key, params[key]));

let headers = {
    "Accept": "application/json",
    "Content-Type": "application/json",
}

fetch(url, {
    method: "GET",
    headers: headers,
})
    .then(response => response.json())
    .then(json => console.log(json));

